import { useState, useEffect, useRef } from "react";

// ─── GOOGLE FONTS ────────────────────────────────────────────────────────────
const FontLoader = () => (
  <style>{`@import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;1,300;1,400&family=DM+Sans:wght@300;400;500;600&display=swap');`}</style>
);

// ─── DESIGN TOKENS ───────────────────────────────────────────────────────────
const tokens = `:root {
--bg:          #0F0D14;
--surface:     #1A1625;
--elevated:    #221D30;
--border:      #2D2740;
--silent:      #3D3550;
--lavender:    #C4A8D4;
--gold:        #D4B896;
--deep-lav:    #8B6FA8;
--soft-bloom:  #E8D5F0;
--text-1:      #EDE8F5;
--text-2:      #9B8FB0;
--text-3:      #5C5270;
--sage:        #7BC8A4;
--amber:       #C4A86A;
--rose:        #C47A7A;
--font-serif:  'Cormorant Garamond', Georgia, serif;
--font-sans:   'DM Sans', system-ui, sans-serif;
--r-sm:        12px;
--r-md:        16px;
--r-lg:        24px;
}
* { box-sizing: border-box; margin: 0; padding: 0; }
body {
background: var(--bg);
color: var(--text-1);
font-family: var(--font-sans);
-webkit-font-smoothing: antialiased;
overflow: hidden;
height: 100vh;
}
.app {
width: 100%;
max-width: 420px;
margin: 0 auto;
height: 100vh;
position: relative;
overflow: hidden;
background: var(--bg);
}
.screen {
position: absolute;
inset: 0;
display: flex;
flex-direction: column;
opacity: 0;
transition: opacity 0.4s ease;
pointer-events: none;
overflow-y: auto;
overflow-x: hidden;
}
.screen.active {
opacity: 1;
pointer-events: all;
}
.serif { font-family: var(--font-serif); }
.t1 { color: var(--text-1); }
.t2 { color: var(--text-2); }
.t3 { color: var(--text-3); }
.card {
background: var(--surface);
border: 1px solid var(--border);
border-radius: var(--r-lg);
padding: 20px;
}
.card-elevated {
background: var(--elevated);
border: 1px solid var(--border);
border-radius: var(--r-lg);
padding: 20px;
}
.btn-primary {
display: flex; align-items: center; justify-content: center;
width: 100%;
padding: 16px 24px;
border-radius: var(--r-md);
border: 1.5px solid var(--lavender);
background: transparent;
color: var(--lavender);
font-family: var(--font-sans);
font-size: 15px;
font-weight: 500;
letter-spacing: 0.02em;
cursor: pointer;
transition: all 0.2s ease;
}
.btn-primary:hover, .btn-primary:active {
background: rgba(196,168,212,0.12);
}
.btn-primary.filled {
background: var(--lavender);
color: var(--bg);
}
.btn-ghost {
display: flex; align-items: center; justify-content: center;
width: 100%;
padding: 14px 24px;
border-radius: var(--r-md);
border: 1px solid var(--border);
background: transparent;
color: var(--text-2);
font-family: var(--font-sans);
font-size: 14px;
cursor: pointer;
transition: all 0.2s ease;
}
.btn-ghost:hover { border-color: var(--silent); color: var(--text-1); }
.btn-choice {
display: flex; align-items: center;
width: 100%;
padding: 16px 20px;
border-radius: var(--r-md);
border: 1.5px solid var(--border);
background: transparent;
color: var(--text-1);
font-family: var(--font-sans);
font-size: 15px;
cursor: pointer;
transition: all 0.2s ease;
text-align: left;
gap: 12px;
}
.btn-choice:hover { border-color: var(--deep-lav); }
.btn-choice.selected {
border-color: var(--lavender);
background: rgba(196,168,212,0.08);
color: var(--lavender);
}
.dot-strip {
display: flex;
gap: 10px;
align-items: center;
}
.dot {
width: 10px; height: 10px;
border-radius: 50%;
transition: all 0.3s ease;
flex-shrink: 0;
}
.dot.trained { background: var(--deep-lav); box-shadow: 0 0 8px rgba(139,111,168,0.5); }
.dot.untrained { background: transparent; border: 1.5px solid var(--silent); }
.dot.today { background: transparent; border: 1.5px solid var(--lavender); animation: pulse 2s infinite; }
.dot.empty { background: var(--border); border-radius: 2px; width: 6px; height: 2px; }
@keyframes pulse {
0%, 100% { box-shadow: 0 0 0 0 rgba(196,168,212,0.4); }
50% { box-shadow: 0 0 0 4px rgba(196,168,212,0); }
}
.checkin-opts {
display: flex;
gap: 10px;
flex-wrap: wrap;
}
.checkin-opt {
flex: 1;
min-width: 80px;
padding: 14px 12px;
border-radius: var(--r-md);
border: 1.5px solid var(--border);
background: transparent;
color: var(--text-2);
font-family: var(--font-sans);
font-size: 13px;
font-weight: 500;
cursor: pointer;
transition: all 0.2s ease;
text-align: center;
line-height: 1.3;
}
.checkin-opt:hover { border-color: var(--deep-lav); color: var(--text-1); }
.checkin-opt.selected {
border-color: var(--lavender);
background: rgba(196,168,212,0.10);
color: var(--lavender);
}
.progress-bar {
height: 2px;
background: var(--border);
border-radius: 1px;
overflow: hidden;
}
.progress-fill {
height: 100%;
background: var(--lavender);
border-radius: 1px;
transition: width 0.4s ease;
}
.insight-card {
border-radius: var(--r-lg);
border: 1px solid var(--border);
overflow: hidden;
background: var(--surface);
}
.insight-header {
padding: 20px 20px 16px;
}
.insight-expand {
border-top: 1px solid var(--border);
padding: 16px 20px;
cursor: pointer;
display: flex;
align-items: center;
gap: 8px;
color: var(--text-2);
font-size: 13px;
transition: color 0.2s;
background: transparent;
width: 100%;
font-family: var(--font-sans);
text-align: left;
}
.insight-expand:hover { color: var(--lavender); }
.insight-body {
padding: 0 20px 20px;
color: var(--text-2);
font-size: 14px;
line-height: 1.7;
display: none;
}
.insight-body.open { display: block; }
.nav {
position: fixed;
bottom: 0;
left: 50%;
transform: translateX(-50%);
width: 100%;
max-width: 420px;
background: rgba(15,13,20,0.95);
backdrop-filter: blur(20px);
border-top: 1px solid var(--border);
display: flex;
padding: 12px 0 max(12px, env(safe-area-inset-bottom));
z-index: 100;
}
.nav-item {
flex: 1;
display: flex;
flex-direction: column;
align-items: center;
gap: 4px;
cursor: pointer;
padding: 4px 0;
color: var(--text-3);
font-size: 10px;
letter-spacing: 0.05em;
transition: color 0.2s;
background: none;
border: none;
font-family: var(--font-sans);
}
.nav-item.active { color: var(--lavender); }
.nav-item svg { width: 20px; height: 20px; }
.divider {
height: 1px;
background: var(--border);
margin: 20px 0;
}
.tag {
display: inline-flex;
align-items: center;
padding: 4px 10px;
border-radius: 100px;
border: 1px solid var(--border);
font-size: 12px;
color: var(--text-2);
gap: 6px;
}
.tag.active {
border-color: var(--lavender);
color: var(--lavender);
background: rgba(196,168,212,0.08);
}
.account-bar {
height: 6px;
border-radius: 3px;
background: var(--border);
overflow: hidden;
}
.account-fill {
height: 100%;
border-radius: 3px;
background: linear-gradient(90deg, var(--deep-lav), var(--lavender));
transition: width 1s ease;
}
.stagger > * {
opacity: 0;
transform: translateY(12px);
animation: staggerIn 0.4s ease forwards;
}
.stagger > *:nth-child(1) { animation-delay: 0.05s; }
.stagger > *:nth-child(2) { animation-delay: 0.12s; }
.stagger > *:nth-child(3) { animation-delay: 0.19s; }
.stagger > *:nth-child(4) { animation-delay: 0.26s; }
.stagger > *:nth-child(5) { animation-delay: 0.33s; }
.stagger > *:nth-child(6) { animation-delay: 0.40s; }
.stagger > *:nth-child(7) { animation-delay: 0.47s; }
.stagger > *:nth-child(8) { animation-delay: 0.54s; }
@keyframes staggerIn {
to { opacity: 1; transform: translateY(0); }
}
.noise-overlay {
position: fixed;
inset: 0;
pointer-events: none;
opacity: 0.025;
background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
background-size: 200px;
z-index: 9999;
}
::-webkit-scrollbar { width: 3px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--silent); border-radius: 2px; }
.safe-top { padding-top: max(48px, env(safe-area-inset-top)); }
.safe-bottom { padding-bottom: max(80px, calc(env(safe-area-inset-bottom) + 68px)); }
.first-screen-glow {
position: absolute;
top: 20%;
left: 50%;
transform: translateX(-50%);
width: 300px;
height: 300px;
background: radial-gradient(ellipse, rgba(196,168,212,0.06) 0%, transparent 70%);
pointer-events: none;
}
.radio-group {
display: flex;
flex-direction: column;
gap: 8px;
}
.radio-item {
display: flex;
align-items: center;
gap: 12px;
padding: 14px 16px;
border-radius: var(--r-md);
border: 1.5px solid var(--border);
cursor: pointer;
transition: all 0.2s;
}
.radio-item:hover { border-color: var(--deep-lav); }
.radio-item.selected { border-color: var(--lavender); background: rgba(196,168,212,0.06); }
.radio-dot {
width: 16px; height: 16px;
border-radius: 50%;
border: 2px solid var(--silent);
flex-shrink: 0;
display: flex; align-items: center; justify-content: center;
transition: all 0.2s;
}
.radio-item.selected .radio-dot {
border-color: var(--lavender);
background: var(--lavender);
}
.radio-item.selected .radio-dot::after {
content: '';
width: 6px; height: 6px;
border-radius: 50%;
background: var(--bg);
}
.community-number {
font-family: var(--font-serif);
font-size: 48px;
font-weight: 300;
color: var(--lavender);
letter-spacing: -0.02em;
line-height: 1;
}
.checkbox-grid {
display: grid;
grid-template-columns: 1fr 1fr;
gap: 8px;
}
.checkbox-item {
padding: 12px 14px;
border-radius: var(--r-md);
border: 1.5px solid var(--border);
cursor: pointer;
font-size: 13px;
color: var(--text-2);
transition: all 0.2s;
display: flex;
align-items: center;
gap: 8px;
background: none;
font-family: var(--font-sans);
text-align: left;
}
.checkbox-item:hover { border-color: var(--deep-lav); color: var(--text-1); }
.checkbox-item.checked {
border-color: var(--lavender);
background: rgba(196,168,212,0.08);
color: var(--lavender);
}
.checkbox-box {
width: 14px; height: 14px;
border-radius: 4px;
border: 1.5px solid var(--silent);
flex-shrink: 0;
transition: all 0.2s;
display: flex; align-items: center; justify-content: center;
}
.checkbox-item.checked .checkbox-box {
background: var(--lavender);
border-color: var(--lavender);
}`;

// ─── ICONS ────────────────────────────────────────────────────────────────────
const Icon = ({ name, size = 20, color = "currentColor" }) => {
  const icons = {
    sun: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="1.5" strokeLinecap="round"><circle cx="12" cy="12" r="4"/><path d="M12 2v2M12 20v2M4.93 4.93l1.41 1.41M17.66 17.66l1.41 1.41M2 12h2M20 12h2M6.34 17.66l-1.41 1.41M19.07 4.93l-1.41 1.41"/></svg>,
    wave: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="1.5" strokeLinecap="round"><path d="M2 12s3-4 5-4 4 4 7 4 5-4 7-4"/><path d="M2 18s3-4 5-4 4 4 7 4 5-4 7-4"/></svg>,
    chart: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="1.5" strokeLinecap="round"><polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/></svg>,
    gear: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="1.5" strokeLinecap="round"><circle cx="12" cy="12" r="3"/><path d="M12 1v4M12 19v4M4.22 4.22l2.83 2.83M16.95 16.95l2.83 2.83M1 12h4M19 12h4M4.22 19.78l2.83-2.83M16.95 7.05l2.83-2.83"/></svg>,
    check: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round"><path d="M20 6L9 17l-5-5"/></svg>,
    book: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="1.5" strokeLinecap="round"><path d="M4 19.5A2.5 2.5 0 0 1 6.5 17H20"/><path d="M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z"/></svg>,
