  const scheduleLabels = { standard: "Consistent", shift: "Shifts / irregular", varies: "Varies a lot" };

  return (
    <div style={{ height: "100%", overflowY: "auto" }}>
      <div style={{ padding: "52px 24px 24px" }} className="stagger">
        <div style={{ fontSize: 11, color: "var(--lavender)", letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 8 }}>Preferences</div>
        <div style={{ fontFamily: "var(--font-serif)", fontSize: 26, fontWeight: 300, color: "var(--text-1)", marginBottom: 28 }}>Settings</div>

        <div className="card" style={{ marginBottom: 12, padding: 0, overflow: "hidden" }}>
          <SectionHeader id="schedule" label="Daily schedule" value={scheduleLabels[schedule]} />
          {section === "schedule" && (
            <div style={{ padding: "0 20px 20px", borderTop: "1px solid var(--border)" }}>
              <div style={{ display: "flex", gap: 10, marginBottom: 16, marginTop: 16 }}>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 11, color: "var(--text-3)", marginBottom: 8 }}>Wake up</div>
                  <select value={wakeTime} onChange={e => setWakeTime(e.target.value)} style={{width: "100%", background: "var(--elevated)", border: "1px solid var(--border)",borderRadius: "var(--r-sm)", padding: "10px 12px", color: "var(--lavender)",fontFamily: "var(--font-sans)", fontSize: 14, cursor: "pointer"}}>
                    {["5:00 AM","5:30 AM","6:00 AM","6:30 AM","7:00 AM","7:30 AM","8:00 AM","8:30 AM","9:00 AM","10:00 AM","11:00 AM","12:00 PM","1:00 PM","2:00 PM","3:00 PM","4:00 PM"].map(t => (<option key={t} value={t} style={{ background: "var(--elevated)" }}>{t}</option>))}
                  </select>
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 11, color: "var(--text-3)", marginBottom: 8 }}>Sleep</div>
                  <select value={sleepTime} onChange={e => setSleepTime(e.target.value)} style={{width: "100%", background: "var(--elevated)", border: "1px solid var(--border)",borderRadius: "var(--r-sm)", padding: "10px 12px", color: "var(--lavender)",fontFamily: "var(--font-sans)", fontSize: 14, cursor: "pointer"}}>
                    {["8:00 PM","9:00 PM","9:30 PM","10:00 PM","10:30 PM","11:00 PM","11:30 PM","12:00 AM","1:00 AM","2:00 AM","3:00 AM","4:00 AM"].map(t => (<option key={t} value={t} style={{ background: "var(--elevated)" }}>{t}</option>))}
                  </select>
                </div>
              </div>
              <div style={{ fontSize: 12, color: "var(--text-3)", marginBottom: 12 }}>Schedule type</div>
              <div className="radio-group" style={{ marginBottom: 16 }}>
                {[{id:"standard",label:"Consistent each week"},{id:"shift",label:"Shifts or irregular"},{id:"varies",label:"It varies a lot"}].map(o => (
                  <div key={o.id} className={`radio-item ${schedule === o.id ? "selected" : ""}`} onClick={() => setSchedule(o.id)} style={{ padding: "10px 14px" }}>
                    <div className="radio-dot" />
                    <span style={{ fontSize: 13, color: schedule === o.id ? "var(--lavender)" : "var(--text-1)" }}>{o.label}</span>
                  </div>
                ))}
              </div>
              <button className="btn-primary" onClick={handleSave} style={{ fontSize: 13, padding: "12px" }}>Save changes</button>
            </div>
          )}
        </div>

        <div className="card" style={{ marginBottom: 12, padding: 0, overflow: "hidden" }}>
          <SectionHeader id="aim" label="Training aim" value={`${trainingDays} days / week`} />
          {section === "aim" && (
            <div style={{ padding: "16px 20px 20px", borderTop: "1px solid var(--border)" }}>
              <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 28, marginBottom: 20 }}>
                <button onClick={() => setTrainingDays(d => Math.max(1, d - 1))} style={{width: 40, height: 40, borderRadius: "50%", border: "1.5px solid var(--border)",background: "transparent", color: "var(--text-2)", cursor: "pointer",display: "flex", alignItems: "center", justifyContent: "center"}}><Icon name="minus" size={14} /></button>
                <div style={{ textAlign: "center" }}>
                  <div style={{ fontFamily: "var(--font-serif)", fontSize: 48, fontWeight: 300, color: "var(--lavender)", lineHeight: 1 }}>{trainingDays}</div>
                  <div style={{ fontSize: 12, color: "var(--text-3)", marginTop: 4 }}>days per week</div>
                </div>
                <button onClick={() => setTrainingDays(d => Math.min(7, d + 1))} style={{width: 40, height: 40, borderRadius: "50%", border: "1.5px solid var(--border)",background: "transparent", color: "var(--text-2)", cursor: "pointer",display: "flex", alignItems: "center", justifyContent: "center"}}><Icon name="plus" size={14} /></button>
              </div>
              <button className="btn-primary" onClick={handleSave} style={{ fontSize: 13, padding: "12px" }}>Save changes</button>
            </div>
          )}
        </div>

        <div className="card" style={{ marginBottom: 12, padding: 0, overflow: "hidden" }}>
          <SectionHeader id="movement" label="Training types" value={`${movements.length} selected`} />
          {section === "movement" && (
            <div style={{ padding: "16px 20px 20px", borderTop: "1px solid var(--border)" }}>
              <div className="checkbox-grid" style={{ marginBottom: 16 }}>
                {["Strength / weights","Running / cardio","Yoga / mobility","Swimming","Cycling","Walking — for me","Team sport","Outdoors / nature","Active play","Work-based movement"].map(t => (
                  <button key={t} className={`checkbox-item ${movements.includes(t) ? "checked" : ""}`} onClick={() => toggleMovement(t)} style={{ fontSize: 12 }}>
                    <div className="checkbox-box">{movements.includes(t) && <Icon name="check" size={9} color="var(--bg)" />}</div>
                    <span>{t}</span>
                  </button>
                ))}
              </div>
              <button className="btn-primary" onClick={handleSave} style={{ fontSize: 13, padding: "12px" }}>Save changes</button>
            </div>
          )}
        </div>

        <div className="card" style={{ marginBottom: 12, padding: 0, overflow: "hidden" }}>
          <SectionHeader id="tone" label="Language and tone" value={toneLabels[tone]} />
          {section === "tone" && (
            <div style={{ padding: "16px 20px 20px", borderTop: "1px solid var(--border)" }}>
              <div className="radio-group" style={{ marginBottom: 16 }}>
                {[{id:"warm",label:"Warm and conversational",sub:"Like a thoughtful friend"},{id:"standard",label:"Clear and straightforward",sub:"Just the information"},{id:"precise",label:"Precise and analytical",sub:"Data-forward language"}].map(o => (
                  <div key={o.id} className={`radio-item ${tone === o.id ? "selected" : ""}`} onClick={() => setTone(o.id)}>
                    <div className="radio-dot" />
                    <div>
                      <div style={{ fontSize: 13, color: tone === o.id ? "var(--lavender)" : "var(--text-1)" }}>{o.label}</div>
                      <div style={{ fontSize: 11, color: "var(--text-3)", marginTop: 2 }}>{o.sub}</div>
                    </div>
                  </div>
                ))}
              </div>
              <button className="btn-primary" onClick={handleSave} style={{ fontSize: 13, padding: "12px" }}>Save changes</button>
            </div>
          )}
        </div>

        <div className="card" style={{ marginBottom: 12, padding: 0, overflow: "hidden" }}>
          <SectionHeader id="notifs" label="Reminders" value={notifs ? "On" : "Off"} />
          {section === "notifs" && (
            <div style={{ padding: "16px 20px 20px", borderTop: "1px solid var(--border)" }}>
              <div className="radio-group" style={{ marginBottom: 16 }}>
                <div className={`radio-item ${notifs ? "selected" : ""}`} onClick={() => setNotifs(true)}>
                  <div className="radio-dot" />
                  <span style={{ fontSize: 13, color: notifs ? "var(--lavender)" : "var(--text-1)" }}>Yes — remind me gently</span>
                </div>
                <div className={`radio-item ${!notifs ? "selected" : ""}`} onClick={() => setNotifs(false)}>
                  <div className="radio-dot" />
                  <span style={{ fontSize: 13, color: !notifs ? "var(--lavender)" : "var(--text-1)" }}>I will check in myself</span>
                </div>
              </div>
              <button className="btn-primary" onClick={handleSave} style={{ fontSize: 13, padding: "12px" }}>Save changes</button>
            </div>
          )}
        </div>

        <div className="card" style={{ marginBottom: 12, padding: 0, overflow: "hidden" }}>
          <SectionHeader id="research" label="Research contribution" value={research ? "Contributing" : "Not yet"} />
          {section === "research" && (
            <div style={{ padding: "16px 20px 20px", borderTop: "1px solid var(--border)" }}>
              <div style={{ fontSize: 13, color: "var(--text-2)", lineHeight: 1.7, marginBottom: 16 }}>Momentum is a research project studying how people build lasting movement habits. Contributing means your anonymised, aggregated behavioral data joins the dataset.<br /><br />You will never be identified. You can withdraw at any time. Your individual data is never shared — only population patterns.</div>
              <div className="radio-group" style={{ marginBottom: 16 }}>
                <div className={`radio-item ${research ? "selected" : ""}`} onClick={() => setResearch(true)}>
                  <div className="radio-dot" />
                  <div>
                    <div style={{ fontSize: 13, color: research ? "var(--lavender)" : "var(--text-1)" }}>Yes — contribute to the research</div>
                    <div style={{ fontSize: 11, color: "var(--text-3)", marginTop: 2 }}>Your patterns help understand everyone's</div>
                  </div>
                </div>
                <div className={`radio-item ${!research ? "selected" : ""}`} onClick={() => setResearch(false)}>
                  <div className="radio-dot" />
                  <span style={{ fontSize: 13, color: !research ? "var(--lavender)" : "var(--text-1)" }}>Not right now</span>
                </div>
              </div>
              <button className="btn-primary" onClick={handleSave} style={{ fontSize: 13, padding: "12px" }}>Save changes</button>
            </div>
          )}
        </div>

        <div style={{ marginTop: 24, marginBottom: 24 }}>
          <div style={{ fontSize: 11, color: "var(--text-3)", letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 12 }}>Account</div>
          {["Privacy controls", "Export my data", "Delete account"].map((item, i) => (
            <button key={item} style={{width: "100%", background: "none", border: "none", borderBottom: i < 2 ? "1px solid var(--border)" : "none",padding: "14px 0", display: "flex", justifyContent: "space-between", alignItems: "center",cursor: "pointer", fontFamily: "var(--font-sans)", color: i === 2 ? "var(--rose)" : "var(--text-2)",fontSize: 14}}>
              {item}<span style={{ color: "var(--text-3)" }}>→</span>
            </button>
          ))}
        </div>

        <div style={{ fontSize: 11, color: "var(--text-3)", textAlign: "center", lineHeight: 1.7, marginBottom: 24 }}>Momentum · Your data is yours<br />Contracts published at momentum.app/transparency</div>

        {saved && (
          <div style={{position: "fixed", bottom: 100, left: "50%", transform: "translateX(-50%)",background: "var(--elevated)", border: "1px solid var(--sage)",borderRadius: 100, padding: "10px 20px",display: "flex", alignItems: "center", gap: 8, zIndex: 200,animation: "staggerIn 0.2s ease forwards"}}>
            <Icon name="check" size={14} color="var(--sage)" />
            <span style={{ fontSize: 13, color: "var(--sage)", fontFamily: "var(--font-sans)" }}>Saved</span>
          </div>
        )}
      </div>
    </div>
  );
};

// ─── NAVIGATION ───────────────────────────────────────────────────────────────
const Nav = ({ active, onNav }) => {
  const items = [
    { id: "today", icon: "sun", label: "Today" },
    { id: "reflect", icon: "wave", label: "Reflect" },
    { id: "insights", icon: "chart", label: "Insights" },
    { id: "community", icon: "users", label: "Community" },
    { id: "settings", icon: "gear", label: "Settings" },
  ];
  return (
    <nav className="nav">
      {items.map(item => (
        <button key={item.id} className={`nav-item ${active === item.id ? "active" : ""}`} onClick={() => onNav(item.id)}>
          <Icon name={item.icon} size={20} />
          <span style={{ fontSize: 9 }}>{item.label}</span>
        </button>
      ))}
    </nav>
  );
};

// ─── MAIN APP ─────────────────────────────────────────────────────────────────
import { loadState, saveState, defaultAppState } from './lib/storage';
import { dateKey } from './lib/date';

export default function MomentumApp() {
  const [appState, setAppState] = useState(() => loadState());

  const updateState = (updates) => {
    setAppState(prev => {
      const next = { ...prev, ...updates };
      saveState(next);
      return next;
    });
  };

  const updateProfile = (updates) => {
    updateState({
      userProfile: { ...appState.userProfile, ...updates }
    });
  };

  const updateCheckIn = (date, updates) => {
    const key = dateKey(date);
    updateState({
      checkIns: {
        ...appState.checkIns,
        [key]: { ...appState.checkIns[key], ...updates }
      }
    });
  };

  const onboardingFlow = ["philosophy", "intention", "signin","schedule", "aim", "movement", "tone", "notifications", "app"];

  const next = () => {
    const idx = onboardingFlow.indexOf(appState.screen);
    if (idx >= 0 && idx < onboardingFlow.length - 1) {
      updateState({ screen: onboardingFlow[idx + 1] });
    }
    if (appState.screen === "notifications") {
      updateState({ inApp: true, screen: "app" });
    }
  };

  const handleNav = (id) => updateState({ navScreen: id });

  const appScreens = {
    today: <TodayScreen entry={appState.checkIns[dateKey()] || {}} setEntry={(updates) => updateCheckIn(new Date(), updates)} />,
    reflect: <ReflectionScreen checkIns={appState.checkIns} />,
    insights: <InsightsScreen checkIns={appState.checkIns} />,
    community: <CommunityScreen />,
    settings: <SettingsScreen userProfile={appState.userProfile} updateProfile={updateProfile} />,
  };

  return (
    <>
      <FontLoader />
      <style>{tokens}</style>
      <div className="noise-overlay" />
      <div className="app">
        {!appState.inApp && (
          <>
            <div className={`screen ${appState.screen === "philosophy" ? "active" : ""}`}><PhilosophyScreen onNext={next} /></div>
            <div className={`screen ${appState.screen === "intention" ? "active" : ""}`}><IntentionScreen onNext={next} onSave={(val) => updateProfile({ foundingIntention: val })} /></div>
            <div className={`screen ${appState.screen === "signin" ? "active" : ""}`}><SignInScreen onNext={next} /></div>
            <div className={`screen ${appState.screen === "schedule" ? "active" : ""}`}><ScheduleScreen onNext={next} step={1} totalSteps={5} profile={appState.userProfile} updateProfile={updateProfile} /></div>
            <div className={`screen ${appState.screen === "aim" ? "active" : ""}`}><AimScreen onNext={next} step={2} totalSteps={5} profile={appState.userProfile} updateProfile={updateProfile} /></div>
            <div className={`screen ${appState.screen === "movement" ? "active" : ""}`}><MovementScreen onNext={next} step={3} totalSteps={5} profile={appState.userProfile} updateProfile={updateProfile} /></div>
            <div className={`screen ${appState.screen === "tone" ? "active" : ""}`}><ToneScreen onNext={next} step={4} totalSteps={5} profile={appState.userProfile} updateProfile={updateProfile} /></div>
            <div className={`screen ${appState.screen === "notifications" ? "active" : ""}`}><NotificationsScreen onNext={next} step={5} totalSteps={5} profile={appState.userProfile} updateProfile={updateProfile} /></div>
          </>
        )}
        {appState.inApp && (
          <>
            <div className={`screen active safe-bottom`}>{appScreens[appState.navScreen]}</div>
            <Nav active={appState.navScreen} onNav={handleNav} />
          </>
        )}
        {!appState.inApp && appState.screen !== "philosophy" && (
          <button onClick={() => updateState({ inApp: true, screen: "app" })} style={{position: "fixed", bottom: 20, right: 20,padding: "8px 14px", borderRadius: 100,background: "rgba(196,168,212,0.1)", border: "1px solid var(--border)",color: "var(--text-3)", fontSize: 11, cursor: "pointer",fontFamily: "var(--font-sans)", zIndex: 1000}}>Skip to app →</button>
        )}
      </div>
    </>
  );
}
